async function seed() {
  try {
    await mongoose.connect(process.env.MONGO_URI);
    console.log('✅ Connected to MongoDB');

    // Clear existing geo data
    await Geo.deleteMany({});
    console.log('🗑️  Cleared existing geo data');

    // Build flat array of documents
    const docs = [];
    for (const state of INDIA_DATA) {
      for (const district of state.districtList) {
        for (const block of district.blockList) {
          docs.push({ state: state.name, district: district.name, block });
        }
      }
    }

    // Insert in bulk
    await Geo.insertMany(docs, { ordered: false });
    console.log(`✅ Inserted ${docs.length} geo records`);
    console.log(`   States: ${INDIA_DATA.length}`);
    console.log(`   Districts: ${INDIA_DATA.reduce((a, s) => a + s.districtList.length, 0)}`);
    console.log(`   Blocks: ${docs.length}`);

    await mongoose.disconnect();
    console.log('✅ Done! Geo data seeded successfully.');
  } catch (err) {
    console.error('❌ Seed failed:', err.message);
    process.exit(1);
  }
}

seed();
